parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const user_id         = body.user_id         || null;
const organization_id = body.organization_id || null;
const name            = body.name            || 'My Workspace';
const lane            = body.lane            || 'Idea';
const stage           = body.stage           || 'Idea';
const access_token    = body.access_token    || null;

if (!user_id)         throw new Error('Missing: user_id');
if (!organization_id) throw new Error('Missing: organization_id');
if (!access_token)    throw new Error('Missing: access_token');

const ALLOWED_LANES = ['Idea', 'Offer', 'Customer', 'Systems'];
const safe_lane = ALLOWED_LANES.includes(lane) ? lane : 'Idea';

const MISSION_SEEDS = {
  Idea: {
    title: 'Validate Your Idea',
    description: 'Stress-test your concept before investing time and money.',
    steps: [
      { title: 'Run the Idea Validator', description: 'Get a 0–100 viability score with strengths, weaknesses, and risks.', tool_key: 'idea-validator', sort_order: 0 },
      { title: 'Kill My Idea (Devil\'s Advocate)', description: "Let Nova argue against your idea. If it survives, it's worth pursuing.", tool_key: 'kill-my-idea', sort_order: 1 },
      { title: 'Define your one-sentence pitch', description: 'Write the sentence you\'d use to explain your idea to a busy investor.', tool_key: null, sort_order: 2 }
    ]
  },
  Offer: {
    title: 'Build Your Core Offer',
    description: 'Define what you sell, who you sell it to, and why they should buy today.',
    steps: [
      { title: 'Build your Offer', description: 'Define promise, deliverables, price, and guarantee.', tool_key: 'offer', sort_order: 0 },
      { title: 'Create your GTM Strategy', description: 'Map target segment, channels, messaging, and 90-day plan.', tool_key: 'gtm-strategy', sort_order: 1 },
      { title: 'Write your positioning sentence', description: "Complete: 'We help [ICP] achieve [outcome] without [pain] in [timeframe].'", tool_key: null, sort_order: 2 }
    ]
  },
  Customer: {
    title: 'Land Your First 10 Customers',
    description: 'Stop waiting for inbound. Map a precision outreach plan.',
    steps: [
      { title: 'Generate First 10 Customers Plan', description: 'Get actionable strategies to land 10 customers in 30 days.', tool_key: 'first-10-customers', sort_order: 0 },
      { title: 'Build Your Follow-Up Sequence', description: 'Create a 5-step sequence that converts cold leads to paying clients.', tool_key: 'followup', sort_order: 1 },
      { title: 'Send your first outreach message', description: 'Pick one prospect and send the first message today.', tool_key: null, sort_order: 2 }
    ]
  },
  Systems: {
    title: 'Launch Your GTM System',
    description: 'Build the engine that generates customers without you as the bottleneck.',
    steps: [
      { title: 'Create your GTM Strategy', description: 'Document the full GTM strategy your team can execute without you.', tool_key: 'gtm-strategy', sort_order: 0 },
      { title: 'Build your Operations Plan', description: 'Design processes and automations that run the business.', tool_key: 'generate-ops-plan', sort_order: 1 },
      { title: 'Identify first automation candidate', description: 'Pick one manual task happening 3× per week and spec it for automation.', tool_key: null, sort_order: 2 }
    ]
  }
};

const seed = MISSION_SEEDS[safe_lane];

return [{
  json: {
    user_id,
    organization_id,
    name,
    lane: safe_lane,
    stage,
    access_token,
    mission_title: seed.title,
    mission_description: seed.description,
    mission_steps: seed.steps,
    now: new Date().toISOString()
  }
}];

const workspace = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const ctx = $('Parse & Build Seed').item.json;
return [{
  json: {
    ...ctx,
    workspace_id: workspace.id
  }
}];

const mission = Array.isArray($input.first().json) ? $input.first().json[0] : $input.first().json;
const ctx = $('Extract Workspace ID').item.json;

const stepRows = ctx.mission_steps.map(s => ({
  mission_id: mission.id,
  title: s.title,
  description: s.description,
  tool_key: s.tool_key,
  sort_order: s.sort_order,
  status: 'pending'
}));

return [{
  json: {
    ...ctx,
    mission_id: mission.id,
    step_rows: stepRows
  }
}];

